package tests;import base.BaseTest;import pages.CocineroPage;import pages.LoginPage;import org.junit.jupiter.api.Assertions;import org.junit.jupiter.api.Test;public class HP04MarcarPedidoEntregadoTest extends BaseTest {    @Test    void cocineroMarcaPedidoComoEntregado() {        try {            System.out.println("Ejecutando HP-04: Marcar pedido como entregado");            LoginPage loginPage = new LoginPage(driver);            loginPage.abrirLogin();            loginPage.iniciarSesion("cocinero", "123");            Thread.sleep(3000);            CocineroPage cocineroPage = new CocineroPage(driver);            int pendientesAntes = cocineroPage.cantidadBotonesComenzarPreparacion();            Assertions.assertTrue(                    pendientesAntes > 0,                    "No existe ningún pedido pendiente para preparar el caso HP-04."            );            cocineroPage.comenzarPreparacion();            Thread.sleep(3000);            int enPreparacionAntes = cocineroPage.cantidadBotonesMarcarComoEntregado();            Assertions.assertTrue(                    enPreparacionAntes > 0,                    "El pedido no pasó correctamente a En Preparación."            );            cocineroPage.marcarComoEntregado();            Thread.sleep(3000);            int enPreparacionDespues = cocineroPage.cantidadBotonesMarcarComoEntregado();            Assertions.assertTrue(                    enPreparacionDespues < enPreparacionAntes,                    "El pedido no fue marcado como entregado correctamente."            );            System.out.println("HP-04 ejecutado correctamente.");        } catch (Exception e) {            Assertions.fail("Error en HP-04: " + e.getMessage());        }    }}